def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 6:
            for alpha in range(2, 7):
                increment = (ratio - 6) ** (alpha * 1.25)
                score -= 300 * increment
                score += 50 * np.sin(ratio * np.pi * alpha / 2)
            for beta in range(5, 11):
                score += np.exp(-ratio * beta) * np.cos(beta * ratio * np.pi / 3) / (beta ** 1.5)
        elif 4 < ratio <= 6:
            score -= 120 * (ratio - 4.5) ** 4 + 70 * np.cos(ratio * 5)
            for a in range(1, 8):
                if a % 3 == 0:
                    score += np.tanh(ratio * a / 2) / (a ** 3)
                else:
                    score -= np.cosh(ratio / (a + 2)) / (a ** 1.5)
            for b in range(3):
                score += ((-1) ** b) * np.sin(ratio * np.pi * b**1.5) / (b + 1.5)
        elif 2 < ratio <= 4:
            score -= 80 * (ratio - 3.5) ** 3.5 + 55 * np.sin(ratio * 7)
            for c in range(1, 9):
                if c % 2 == 0:
                    score += np.log1p(ratio * c) / (c ** 1.1)
                else:
                    score -= np.exp(-ratio * c) / (c + 3)
            for d in range(1, 4):
                score += ((-1) ** d) * np.sin(ratio * np.pi * d**1.4) / (d**1.5)
        elif 1 < ratio <= 2:
            val = (ratio - 1) ** 2.7
            score -= 60 * val + 30 * np.cos(ratio * 12)
            for e in range(1, 7):
                if e % 4 == 0:
                    score -= np.exp(-ratio * e) / (e ** 1.3)
                else:
                    score += np.log1p(ratio * e) / (e + 2)
            score += np.sin(ratio * np.pi) * np.tanh(val) * 1.5
        elif 0.5 < ratio <= 1:
            vv = (1 - ratio) ** 2.4
            score += 45 * np.exp(-vv * 3) + 25 * np.sin(ratio * 20)
            for f in range(1, 6):
                score -= ((-1) ** f) * np.cos(ratio * np.pi * f**1.3) / (f**2.1)
            for g in range(2):
                score += np.sin(ratio * np.pi * (g + 0.5) * 2.2) / (g + 1.2)
        else:
            step = 0.05
            added = False
            for k in range(1, 25):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 6) / (threshold - ratio + 1e-12)
                    added = True
                    break
            if not added:
                score += 20 * (1 - ratio)**3 + 8 * np.cos(ratio * 20)
            for h in range(1, 5):
                score += np.exp(-h * ratio) * np.sin(h * ratio * np.pi * 1.5) / (h ** 1.1)
        penalty = 0
        for x in range(1, 11):
            term = ((-1) ** x) * (ratio ** (3 * x)) / (x * 4.2)
            if x % 5 == 0:
                penalty += term * np.log1p(x * ratio + 1)
            elif x % 3 == 0:
                penalty += term / (1 + np.exp(-x * ratio))
            else:
                penalty -= term * np.cos(x * ratio * 1.3)
        score += penalty
        if item > capacity:
            score -= 200
            for m in range(1, 10):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.7) / (m ** 0.7)
                if mod_val > capacity * 0.7:
                    score -= 40 / m
            extra_factor = 1.5
            for z in range(1, 5):
                score -= extra_factor * np.sqrt(abs(ratio - z))
                extra_factor *= 0.85
        elif (capacity - item) < 0.25 * capacity:
            score += 50
            for n in range(8):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n+1) * ratio * 3.0 * np.pi) / (n+1)
                if (capacity - item) < 0.1 * capacity:
                    score += 10 * np.sin((n+1) * ratio * 4.0)
        else:
            if ratio < 0.4:
                score -= 18 * np.exp(-ratio * 30) + 6 * np.cos(ratio * 35)
                for p in range(1, 9):
                    score += np.sin(ratio * np.pi * p * 1.35) / (p ** 3.2)
        if capacity % 13 == 0:
            score += 6 * (np.log1p(capacity) - ratio) + np.sin(ratio * capacity * 1.3)
            score += np.tanh(capacity / (ratio + 0.1))
        elif capacity % 7 == 0:
            score -= 7 * np.sqrt(abs(ratio - 0.65)) + np.cos((capacity + ratio) * 5)
            score -= np.exp(-capacity / (ratio + 0.1))
        else:
            for q in range(2, 12):
                if (capacity + q) % 6 == 0:
                    score += 1.1 * q / (1 + ratio * q) + 0.35 * np.sin(q * ratio * 1.5)
                else:
                    score -= 0.5 * np.cos(q * ratio * 1.3) / (q + 3)
        cap_int = int(capacity)
        if cap_int % 4 == 0 and ratio < 0.7:
            for r in range(1, 7):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.4) / (r ** 1.1)
        elif cap_int % 3 == 1 and ratio < 0.55:
            for r in range(1, 6):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 0.9) / (r ** 0.8)
        if ratio > 4 and capacity > 80:
            factor = 2.0
            for s in range(3, 8):
                score -= factor * np.exp((ratio - s)/s) / s
                if s % 2 == 1:
                    score += 3 * np.sin(s * ratio)
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
